export function proxyFields<L extends Logic = Logic>(wrapper: LogicWrapper<L>): void {
  const reservedProxiedKeys = ['path', 'pathString', 'props'] as ['path', 'pathString', 'props']
  for (const key of reservedProxiedKeys) {
